ruleExplore.coverUrl:
class.bookname@tag.a.0@href<js>
var id = result.match(/(\d+)\/?$/)[1];
var iid = parseInt(id/1000);
'https://www.oldtimescc.cc/files/article/image/'+iid+'/'+id+'/'+id+'s.jpg';
</js>

